import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Badge,
  Divider,
  Spacer,
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface PeriodicElement {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: PeriodicElement[];
}

/**
 * Maps element categories to design system color tokens.
 */
const getCategoryColor = (category: string = '') => {
  const normalized = category.toLowerCase();
  switch (normalized) {
    case 'noble-gas':
      return 'var(--ggui-color-info-500)';
    case 'halogen':
      return 'var(--ggui-color-warning-500)';
    case 'nonmetal':
      return 'var(--ggui-color-success-500)';
    case 'alkali':
      return 'var(--ggui-color-error-500)';
    case 'alkaline-earth':
      return 'var(--ggui-color-primary-500)';
    case 'transition-metal':
      return 'var(--ggui-color-neutral-500)';
    case 'post-transition-metal':
      return 'var(--ggui-color-neutral-400)';
    case 'metalloid':
      return 'var(--ggui-color-info-400)';
    case 'lanthanide':
      return 'var(--ggui-color-primary-300)';
    case 'actinide':
      return 'var(--ggui-color-primary-400)';
    default:
      return 'var(--ggui-color-outline)';
  }
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedId, setSelectedId] = useState<number | null>(null);

  // Filter logic: compute matches but keep all elements in grid for structure
  const elementStates = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    return elements.map((el) => {
      const isMatch =
        !query ||
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query);
      return { ...el, isMatch };
    });
  }, [elements, searchQuery]);

  // Find the currently selected element
  const selectedElement = useMemo(
    () => elements.find((el) => el.atomicNumber === selectedId),
    [elements, selectedId]
  );

  // Extract unique categories for the legend
  const categories = useMemo(() => {
    const cats = Array.from(new Set(elements.map((el) => el.category).filter(Boolean)));
    return (cats as string[]).sort();
  }, [elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header Area */}
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={2}>Periodic Table of Elements</Heading>
          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="label" size="sm">Search Elements</Text>
            <SearchField
              placeholder="Search by name or symbol..."
              value={searchQuery}
              onChange={setSearchQuery}
              size="md"
            />
          </Stack>
        </Stack>

        <Divider margin="var(--ggui-spacing-0)" />

        {/* The Grid */}
        <Box style={{ overflowX: 'auto', padding: 'var(--ggui-spacing-2)' }}>
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(var(--ggui-spacing-16), 1fr))',
              gap: 'var(--ggui-spacing-1)',
              minWidth: 'var(--ggui-spacing-256)',
            }}
          >
            {elementStates.map((element) => {
              const categoryColor = getCategoryColor(element.category);
              const isSelected = selectedId === element.atomicNumber;
              const opacity = element.isMatch ? 1 : 0.2;

              return (
                <div
                  key={element.atomicNumber}
                  onClick={() => setSelectedId(element.atomicNumber || null)}
                  style={{
                    gridRow: element.row,
                    gridColumn: element.col,
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    outline: 'none',
                    border: 'none',
                    background: 'none',
                    padding: 0,
                    margin: 0,
                  }}
                >
                  <Card
                    padding="var(--ggui-spacing-2)"
                    radius="md"
                    shadow={isSelected ? 'md' : 'none'}
                    style={{
                      flex: 1,
                      opacity,
                      background: 'var(--ggui-color-surfaceVariant)',
                      borderLeft: `var(--ggui-spacing-1) solid ${categoryColor}`,
                      border: isSelected
                        ? `var(--ggui-spacing-0.5) solid var(--ggui-color-primary-600)`
                        : undefined,
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-0)" align="stretch" style={{ height: '100%' }}>
                      <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                        {element.atomicNumber}
                      </Text>
                      <Spacer size="flex" />
                      <Text
                        align="center"
                        weight="bold"
                        size="xl"
                        color="var(--ggui-color-onSurface)"
                      >
                        {element.symbol}
                      </Text>
                      <Spacer size="flex" />
                      <Text
                        variant="caption"
                        size="xs"
                        align="center"
                        truncate
                        color="var(--ggui-color-onSurfaceVariant)"
                      >
                        {element.name}
                      </Text>
                    </Stack>
                  </Card>
                </div>
              );
            })}
          </Box>
        </Box>

        {/* Legend */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-3)" wrap align="center">
          <Text variant="label" size="sm">Categories:</Text>
          {categories.map((cat) => (
            <Badge key={cat} variant="default">
              <Stack direction="horizontal" gap="var(--ggui-spacing-1)" align="center">
                <Box
                  style={{
                    width: 'var(--ggui-spacing-2)',
                    height: 'var(--ggui-spacing-2)',
                    borderRadius: 'var(--ggui-spacing-0.5)',
                    background: getCategoryColor(cat),
                  }}
                />
                <Text size="sm">{cat}</Text>
              </Stack>
            </Badge>
          ))}
        </Stack>

        {/* Detail Panel */}
        {selectedElement && (
          <Box>
            <Card radius="lg" shadow="md" padding="var(--ggui-spacing-6)" border>
              <Stack direction="horizontal" gap="var(--ggui-spacing-8)" wrap align="start">
                {/* Large Symbol Display */}
                <Box
                  style={{
                    width: 'var(--ggui-spacing-32)',
                    height: 'var(--ggui-spacing-32)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    borderRadius: 'var(--ggui-shape-radius-lg)',
                    background: 'var(--ggui-color-surfaceVariant)',
                    border: `var(--ggui-spacing-1) solid ${getCategoryColor(selectedElement.category)}`,
                  }}
                >
                  <Text size="xs" variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    {selectedElement.atomicNumber}
                  </Text>
                  <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">
                    {selectedElement.symbol}
                  </Text>
                </Box>

                {/* Metadata */}
                <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
                  <Stack gap="var(--ggui-spacing-1)">
                    <Heading level={3}>{selectedElement.name}</Heading>
                    <Badge variant="primary" style={{ alignSelf: 'start' }}>
                      {selectedElement.category}
                    </Badge>
                  </Stack>

                  <Box
                    style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fit, minmax(var(--ggui-spacing-35), 1fr))',
                      gap: 'var(--ggui-spacing-6)',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                        Atomic Number
                      </Text>
                      <Text weight="medium">{selectedElement.atomicNumber}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                        Atomic Weight
                      </Text>
                      <Text weight="medium">{selectedElement.atomicWeight} u</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                        Symbol
                      </Text>
                      <Text weight="medium">{selectedElement.symbol}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                        Category
                      </Text>
                      <Text weight="medium" style={{ textTransform: 'capitalize' }}>
                        {selectedElement.category?.replace('-', ' ')}
                      </Text>
                    </Stack>
                  </Box>
                </Stack>
              </Stack>
            </Card>
          </Box>
        )}
      </Stack>
    </Container>
  );
}
